import{_ as s,o as e,c as a,Q as n}from"./chunks/framework.2275ac6f.js";const l="/assets/image.8cdb5295.png",p="/assets/image-1.96648117.png",r="/assets/image-2.0ca54435.png",u=JSON.parse('{"title":"Windows Server 2022 下安装B650E-E的驱动","description":"","frontmatter":{"title":"Windows Server 2022 下安装B650E-E的驱动","date":"2024-06-10T13:58:44.000Z","tags":["Windows"]},"headers":[{"level":2,"title":"网卡驱动","slug":"网卡驱动","link":"#网卡驱动","children":[{"level":3,"title":"0. Intel官网下载驱动","slug":"_0-intel官网下载驱动","link":"#_0-intel官网下载驱动","children":[]},{"level":3,"title":"1. 找到网卡的硬件ID","slug":"_1-找到网卡的硬件id","link":"#_1-找到网卡的硬件id","children":[]},{"level":3,"title":"2. 修改驱动","slug":"_2-修改驱动","link":"#_2-修改驱动","children":[]},{"level":3,"title":"3. 安装驱动","slug":"_3-安装驱动","link":"#_3-安装驱动","children":[]}]}],"relativePath":"src/Windows/Windows Server 2022 下安装B650E-E的驱动.md","lastUpdated":1718000534000}'),t={name:"src/Windows/Windows Server 2022 下安装B650E-E的驱动.md"},o=n('<h1 id="windows-server-2022-下安装b650e-e的驱动" tabindex="-1">Windows Server 2022 下安装B650E-E的驱动 <a class="header-anchor" href="#windows-server-2022-下安装b650e-e的驱动" aria-hidden="true">#</a></h1><h2 id="网卡驱动" tabindex="-1">网卡驱动 <a class="header-anchor" href="#网卡驱动" aria-hidden="true">#</a></h2><p>该章内容参考自<a href="https://www.quarkbook.com/?p=1414" target="_blank" rel="noreferrer">Windows Server 2022安装Intel I225-V/I226-V驱动</a></p><p>B650E-E的网卡型号是 Intel I225V 2.5Gb, 属于桌面端产品线，-LM后缀的才属于商业端产品线，默认情况下，Windows Server只能安装商业端产品线的网卡驱动。我们通过魔改配置文件可以绕过这一限制。</p><h3 id="_0-intel官网下载驱动" tabindex="-1">0. Intel官网下载驱动 <a class="header-anchor" href="#_0-intel官网下载驱动" aria-hidden="true">#</a></h3><p><a href="https://www.intel.cn/content/www/cn/zh/products/sku/184676/intel-ethernet-controller-i225v/downloads.html" target="_blank" rel="noreferrer">Intel I225-V驱动</a></p><h3 id="_1-找到网卡的硬件id" tabindex="-1">1. 找到网卡的硬件ID <a class="header-anchor" href="#_1-找到网卡的硬件id" aria-hidden="true">#</a></h3><p>安装好Windows Server 2022之后，在设备管理器中找到网卡，然后右键-&gt;属性-&gt;详细信息。选择硬件ID，记下第一行的硬件ID。</p><p><img src="'+l+`" alt=""></p><p>I225-V B3的硬件ID是 <code>PCI\\VEN_8086&amp;DEV_125C&amp;SUBSYS_00008086&amp;REV_04</code></p><p>在驱动程序的inf文件中查找得知，I226网卡ID为</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">PCI\\VEN_8086&amp;DEV_125C</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">//I225-V B3 ID为：PCI\\VEN_8086&amp;DEV_15F3&amp;REV_03</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_2-修改驱动" tabindex="-1">2. 修改驱动 <a class="header-anchor" href="#_2-修改驱动" aria-hidden="true">#</a></h3><p>下载驱动之后，解压驱动，找打并打卡<code>PRO2500\\Winx64\\WS2022\\e2f.inf</code>文件。</p><p>然后在这个文件里面搜素上面拿到的硬件ID <code>PCI\\VEN_8086&amp;DEV_125C</code>。找到这一行之后，将这一行复制到节点<code>[Intel.NTamd64.10.0...17763]</code>下面：</p><p><img src="`+p+`" alt=""></p><h3 id="_3-安装驱动" tabindex="-1">3. 安装驱动 <a class="header-anchor" href="#_3-安装驱动" aria-hidden="true">#</a></h3><p>进入Windows Server 2022，在CMD（管理员身份）中依次输入下面两条命令，然后重启机器。</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">bcdedit</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-set</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">loadoptions</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">DISABLE_INTEGRITY_CHECKS</span></span>
<span class="line"><span style="color:#FFCB6B;">bcdedit</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-set</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">TESTSIGNING</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">ON</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这一步使为了禁用驱动程序签名和开启测试模式，修改了inf之后，过不了签名验证，但是禁用驱动程序签名验证之后，就可以正常安装了。</p><p>重启之后，在设备管理器中，右键需要安装驱动的网卡，选择“更新驱动程序和软件”。</p><p><img src="`+r+`" alt=""></p><p>然后选择“浏览我的电脑以查找驱动程序”，找到刚刚修改的驱动，点击下一步，选择“始终安装此驱动程序软件”。然后I226-V的驱动就安装好了。</p><p>驱动都安装完成之后，在CMD（管理员身份）中依次输入下面两条命令，关闭测试模式。</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">bcdedit</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-set</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">loadoptions</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">ENABLE_INTEGRITY_CHECKS</span></span>
<span class="line"><span style="color:#FFCB6B;">bcdedit</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">-set</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">TESTSIGNING</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">OFF</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,25),i=[o];function c(d,_,h,E,b,m){return e(),a("div",null,i)}const D=s(t,[["render",c]]);export{u as __pageData,D as default};
